#include<bits/stdc++.h>
using namespace std;
long long n,m;
vector<pair<long long,long long>> mp[100010],mp1[100010];
long long dfn[100010],siz[100010],scc[100010],scccnt,dp[100010],dfncnt,low[100010],in[100010];
bool instk[100010];
stack<long long> stk;
void tarjan(long long x)
{
    instk[x]=1;
    low[x]=dfn[x]=++dfncnt;
    stk.push(x);
    for(auto i:mp[x])
    {
        long long v=i.first;
        if(!dfn[v])
        {
            tarjan(v);
            low[x]=min(low[x],low[v]);
        }
        else if(instk[v])
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
    if(low[x]==dfn[x])
    {
        long long top;
        scccnt++;
        do
        {
            top=stk.top();
            stk.pop();
            scc[top]=scccnt;
            siz[scccnt]++;
            instk[top]=0;
        }while(top!=x);
    }
}
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=m;i++)
    {
        long long t,a,b;
        scanf("%lld%lld%lld",&t,&a,&b);
        if(t==1)
        {
            mp[a].push_back(make_pair(b,0));
            mp[b].push_back(make_pair(a,0));
        }
        else if(t==2)
        {
            mp[a].push_back(make_pair(b,1));
        }
        else if(t==3)
        {
            mp[b].push_back(make_pair(a,0));
        }
        else if(t==4)
        {
            mp[b].push_back(make_pair(a,1));
        }
        else
        {
            mp[a].push_back(make_pair(b,0));
        }
    }
    for(long long i=1;i<=n;i++)
    {
        if(!dfn[i])
        {
            tarjan(i);
        }
    }
    for(long long i=1;i<=n;i++)
    {
        for(auto j:mp[i])
        {
            long long v=j.first,val=j.second;
            if(scc[i]!=scc[v])
            {
                mp1[scc[i]].push_back(make_pair(scc[v],val));
                in[scc[v]]++;
            }
            else if(val)
            {
                printf("-1");
                return 0;
            }
        }
    }
    queue<long long> q;
    long long ans=0;
    for(long long i=1;i<=scccnt;i++)
    {
        if(in[i]==0)
        {
            q.push(i);
            dp[i]=1;
        }
    }
    while(!q.empty())
    {
        long long t=q.front();
        q.pop();
        ans+=dp[t]*siz[t];
        for(auto i:mp1[t])
        {
            long long v=i.first,val=i.second;
            if(dp[v]<dp[t]+val)
            {
                dp[v]=dp[t]+val;
            }
            in[v]--;
            if(in[v]==0)
            {
                q.push(v);
            }
        }
    }
    printf("%lld",ans);
    return 0;
}
